# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor._

case class Deposit(amount: Double)
case class Withdrawal(amount: Double)
case class AccountBalance

class AccountActor extends Actor {
  var balance: Double = 0.0

  override def receive: Receive = {
    case Deposit(depositedAmount) =>
      balance += depositedAmount
      println(s"Deposited $depositedAmount, new balance: $balance")

    case Withdrawal(withdrawnAmount) if withdrawnAmount > balance =>
      println(s"Insufficient funds for withdrawal of $withdrawnAmount, current balance: $balance")

    case Withdrawal(withdrawnAmount) =>
      balance -= withdrawnAmount
      println(s"Withdrew $withdrawnAmount, new balance: $balance")

    case AccountBalance =>
      println(s"Current account balance: $balance")
  }
}